parameters.functionCode:
// Extract burn event data from relay webhook payload
const body = $input.item.json.body || $input.item.json;

return [{
  json: {
    hash:       body.hash       || body.blob_hash  || 'unknown',
    sector:     body.sector     || 'unknown',
    device_id:  body.device_id  || body.device     || 'unknown',
    bytes:      body.bytes      || body.size        || 0,
    timestamp:  body.ts         || new Date().toISOString(),
    api_key_prefix: (body.api_key || '').slice(0, 8) + '...',
    event:      'burn',
  }
}];

values.content:
=A PARAMANT Ghost Pipe secure file transfer just completed (burned after read).

Transfer metadata:
- Sector: {{ $json.sector }}
- Hash prefix: {{ $json.hash.slice(0, 16) }}...
- Bytes transferred: {{ $json.bytes }}
- Device: {{ $json.device_id }}
- Timestamp: {{ $json.timestamp }}

Write a 2-sentence security audit note confirming this transfer. Note any anomalies if: bytes=0, sector is unusual, or device_id looks non-standard. Be concise and professional. Format: plain text, no markdown.

parameters.functionCode:
// Build structured audit log entry
const burn  = $('Extract Burn Data').item.json;
const audit = $input.item.json.text || $input.item.json.content || '';

const entry = {
  timestamp:  burn.timestamp,
  event:      'burn',
  sector:     burn.sector,
  hash:       burn.hash,
  bytes:      burn.bytes,
  device_id:  burn.device_id,
  api_key:    burn.api_key_prefix,
  audit_note: audit.trim(),
  flagged:    burn.bytes === 0 || audit.toLowerCase().includes('anomal') || audit.toLowerCase().includes('unusual'),
};

console.log('[PARAMANT audit]', JSON.stringify(entry));
return [{ json: entry }];

